-- Add new schema named "bronze_history"
CREATE SCHEMA IF NOT EXISTS "bronze_history";
-- Create "vault_pki_certificates_history" table
CREATE TABLE "bronze_history"."vault_pki_certificates_history" (
  "history_id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "valid_from" timestamptz NOT NULL,
  "valid_to" timestamptz NULL,
  "collected_at" timestamptz NOT NULL,
  "first_collected_at" timestamptz NOT NULL,
  "resource_id" character varying NOT NULL,
  "vault_name" character varying NOT NULL,
  "mount_path" character varying NOT NULL,
  "serial_number" character varying NOT NULL,
  "common_name" character varying NULL,
  "issuer_cn" character varying NULL,
  "subject_cn" character varying NULL,
  "sans" character varying NULL,
  "key_type" character varying NULL,
  "key_bits" bigint NULL,
  "signing_algo" character varying NULL,
  "not_before" timestamptz NULL,
  "not_after" timestamptz NULL,
  "is_revoked" boolean NOT NULL DEFAULT false,
  "revoked_at" timestamptz NULL,
  "certificate_pem" character varying NULL,
  PRIMARY KEY ("history_id")
);
-- Create index "bronzehistoryvaultpkicertificate_collected_at" to table: "vault_pki_certificates_history"
CREATE INDEX "bronzehistoryvaultpkicertificate_collected_at" ON "bronze_history"."vault_pki_certificates_history" ("collected_at");
-- Create index "bronzehistoryvaultpkicertificate_resource_id_valid_from" to table: "vault_pki_certificates_history"
CREATE INDEX "bronzehistoryvaultpkicertificate_resource_id_valid_from" ON "bronze_history"."vault_pki_certificates_history" ("resource_id", "valid_from");
-- Create index "bronzehistoryvaultpkicertificate_valid_to" to table: "vault_pki_certificates_history"
CREATE INDEX "bronzehistoryvaultpkicertificate_valid_to" ON "bronze_history"."vault_pki_certificates_history" ("valid_to");
-- Create index "bronzehistoryvaultpkicertificate_vault_name" to table: "vault_pki_certificates_history"
CREATE INDEX "bronzehistoryvaultpkicertificate_vault_name" ON "bronze_history"."vault_pki_certificates_history" ("vault_name");
